//---------------------------------------------------------
scwin.f_Set = async function (gubun) {
  switch (gubun) {
    case "INIT":
      //초기화
      $c.gus.cfDisableKeyData($p); // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
      //scwin.f_setDisabledComp(true);
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_FCopy, btn_Cancel, btn_Save, btn_Save_top, btn_Delete, btn_Update, btn_Update_top, btn_FSave, btn_FDelete, btn_FUpdate, btn_FCancel, btn_1_N, btn_3, btn_4, btn_8, btn_10, btn_Upload, btn_AddCntr, btn_AddCntr1, btn_DelRow2, grpBtn1, pu_departmentChange]);
      $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Retrieve]);
      scwin.statusFlag = "I";
      break;
    case "RETRIEVE":
      //조회모드
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Save_top, btn_Cancel, btn_AddCntr, btn_AddCntr1, btn_DelRow2, grpBtn1, btn_FCancel, btn_FSave, grpBtn2, grpBtn3, grpBtn4, btn_FCopyRow3]);
      $c.gus.cfEnableBtnOnly($p, [btn_Copy, btn_FCopy, btn_Create, btn_Delete, btn_FDelete, btn_Retrieve, btn_1_N, btn_4, btn_8, btn_10, pu_departmentChange, btn_13, btn_14, btn_Hblchg, btn_Upload]);
      // 그리드 수정 못하게 한다.
      gr_ocContList.setReadOnly("grid", true);
      gr_selling.setReadOnly("grid", true);
      gr_partner.setReadOnly("grid", true);
      gr_buying.setReadOnly("grid", true);
      if (scwin.statusFlag == "C") {
        $c.gus.cfDisableBtnOnly($p, [btn_Update, btn_Update_top, btn_FUpdate]);
      } else {
        $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Update_top, btn_FUpdate]);
      }
      $c.gus.cfEnableObjects($p, [cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno, cnd_ed_hhmblno]); // 조회조건.
      scwin.statusFlag = ""; // flag null
      break;
    case "CREATE":
      //신규
      $c.gus.cfEnableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_FCopy, btn_Create, btn_Update, btn_Update_top, btn_Retrieve, btn_Delete, btn_4, btn_8, btn_10, pu_departmentChange, btn_FUpdate, btn_FDelete]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Save_top, btn_Cancel, btn_1, btn_1_N, btn_1_P, btn_1_B, btn_2, btn_2_P, btn_2_B, btn_3, btn_AddCntr, btn_AddCntr1, btn_FSave, btn_FCancel, grpBtn1, grpBtn2, grpBtn3, grpBtn4, btn_FCopyRow3, pu_ResultdateChange, btn_Upload, btn_DelRow2]);
      // 그리드 수정 가능
      gr_ocContList.setReadOnly("grid", false);
      gr_selling.setReadOnly("grid", false);
      gr_partner.setReadOnly("grid", false);
      gr_buying.setReadOnly("grid", false);
      $c.gus.cfDisableObjects($p, [cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno, cnd_ed_hhmblno]); // 조회조건.
      $c.gus.cfEnableObjects($p, [cnd_ed_hhblno, cnd_lc_autono]); // 조회조건.
      scwin.statusFlag = "C";
      break;
    case "UPDATE":
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_FCopy, btn_Update, btn_Update_top, btn_Create, btn_Retrieve, btn_Delete, btn_4, btn_8, btn_10, btn_FUpdate, btn_FDelete, btn_Hblchg, pu_departmentChange]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Save_top, btn_Cancel, btn_AddCntr, btn_AddCntr1, btn_FSave, btn_FCancel, grpBtn1, grpBtn2, grpBtn3, grpBtn4, btn_FCopyRow3, pu_ResultdateChange, btn_Upload, btn_DelRow2]);
      $c.gus.cfDisableKey($p);
      // 그리드 수정 가능
      gr_ocContList.setReadOnly("grid", false);
      gr_selling.setReadOnly("grid", false);
      gr_partner.setReadOnly("grid", false);
      gr_buying.setReadOnly("grid", false);
      $c.gus.cfDisableObjects($p, [cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno, cnd_ed_hhmblno, ed_hhbkgno, lc_hhbkgseq]); // 조회조건,booking no
      scwin.statusFlag = "U";
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Save_top, btn_Delete, btn_Cancel, btn_FSave, btn_FDelete, btn_FCancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Update_top, btn_Create, btn_FUpdate]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};
