scwin.f_Retrieve = async function () {
  if ($c.util.isEmpty($p, cnd_ed_hhblno.getValue())) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House No"]);
    return;
  }
  cnd_lc_mhno.focus(); // B/L No 빠져나올때 event처리 .
  dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
  dma_retrieve.set("hhblno", cnd_ed_hhblno.getValue());
  dma_retrieve.set("mhno", cnd_lc_mhno.getValue());
  dma_retrieve.set("hhio", scwin.hd_hhio);
  dma_retrieve.set("mhio", scwin.hd_hhio);

  //Booking Seq 넣어 주기.
  ds_bkseq.removeAll();
  scwin._insertRow(ds_bkseq);
  if (cnd_lc_autono.getValue() == "DIRECT") {
    await $c.sbm.execute($p, sbm_retrieveMhno);
    await $c.sbm.execute($p, sbm_retrieve);
  } else {
    await $c.sbm.execute($p, sbm_retrieve);
  }
  txt_blpic.setValue("");
  if (ed_blpic.getValue() != "") {
    scwin.f_PopUp("B/L PIC", "T");
  }
  gr_selling.setHeaderDisabled('chk', true);
  gr_partner.setHeaderDisabled('chk', true);
  gr_buying.setHeaderDisabled('chk', true);
};
