scwin.f_Retrieve2 = async function () {
  //상단을 조회하지 않았거나, 결과값이 없을 경우
  if (ds_houseblList.getRowCount() < 1) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_018, ["Exchange Rate Information", "상단의 Search"]); // @이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오.
    return;
  }
  if (srch_ed_hhblno.getValue().trim() == "") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House No"]); // @은(는) 필수 입력 항목입니다.
    return;
  }
  if (ds_sellingUnit.getRowCount() == 0) await scwin.f_allUnitLoading();
  cnd_lc_mhno2.focus(); // B/L No 빠져나올때 event처리 .
  dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
  dma_retrieve.set("mhno", cnd_lc_mhno2.getValue());
  dma_retrieve.set("hhio", scwin.hd_hhio);
  dma_retrieve.set("hhblno2", srch_ed_hhblno.getValue());
  //기존에 조회된 행이 있다면 재조회 안되도록함 개별검색은 재조회 가능
  if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(ds_selling.getRowPosition(), "tabIndex") == "") {
    alert("조회된 Selling데이터가 있습니다.\nSelling데이터가 0건일 경우 조회가능합니다.");
  } else {
    $c.sbm.execute($p, sbm_retrieveSelling);
  }
  if (ds_partner.getRowCount() > 0 && ds_partner.getCellData(ds_partner.getRowPosition(), "tabIndex") == "") {
    alert("조회된 Partner데이터가 있습니다.\nPartner데이터가 0건일 경우 조회가능합니다.");
  } else {
    $c.sbm.execute($p, sbm_retrievePartner);
  }
  if (ds_buying.getRowCount() > 0 && ds_buying.getCellData(ds_buying.getRowPosition(), "tabIndex") == "") {
    alert("조회된 Buying데이터가 있습니다.\nBuying데이터가 0건일 경우 조회가능합니다.");
  } else {
    $c.sbm.execute($p, sbm_retrieveBuying);
    //dataSetDebug(ds_buying,true);
  }
  //cmd anable
  $c.gus.cfEnableObj($p, srch_ed_hhblno, true);
  $c.gus.cfEnableObj($p, cnd_lc_mhno2, true);
};
scwin.f_allUnitLoading = async function (forceLoad) {
  var cnt = scwin._getCntParams();
  var key = cnt.join(",");
  if (!forceLoad && scwin._lastUnitParams === key && ds_sellingUnit.getRowCount() > 0) return;
  scwin._lastUnitParams = key;
  var gauce = await scwin.f_commCodeSync("SeaImportHouseEBC", "retriveUnitList", cnt[0], cnt[1], cnt[2], cnt[3]);
  ds_sellingUnit.removeAll();
  ds_partnerUnit.removeAll();
  ds_buyingUnit.removeAll();
  if (gauce) {
    ds_sellingUnit.setJSON(gauce);
    ds_partnerUnit.setJSON(gauce);
    ds_buyingUnit.setJSON(gauce);
  }
};

