scwin.f_FreightDelete = async function () {
  if (ds_selling.getRowCount() == "0" && ds_partner.getRowCount() == "0" && ds_buying.getRowCount() == "0") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Freight Information"]); //  @이(가) 존재하지 않습니다.
    return;
  }
  // invoice check
  scwin.f_invoiceCheck(); // invoice Check
  if (scwin.invoiceCheck == "1") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]); // @은(는) @할 수 없습니다.
    return;
  }
  if ($c.win.confirm($p, E_MSG_CM_CRM_004)) {
    //삭제하시겠습니까?
    ds_selling.removeAll(); // selling 전체삭제.
    ds_partner.removeAll(); // partner 전체삭제.
    ds_buying.removeAll(); // buying 전체삭제.
    var sbmResult = await $c.sbm.execute($p, sbm_deleteFreight);
    if (scwin.sbm_tr_deleteFreight_submitdone) {
      scwin.sbm_tr_deleteFreight_submitdone(sbmResult);
    }
    ;

    // dataset초기화
    ds_selling.removeAll();
    ds_partner.removeAll();
    ds_buying.removeAll();

    //cmd anable
    $c.gus.cfEnableObj($p, cnd_ed_hhblno, true);
    $c.gus.cfEnableObj($p, cnd_lc_mhno, true);
    cnd_ed_hhblno.focus();
    scwin.f_Set("INIT");
  }
};
scwin.isEmpty = function (value) {
  if (value == null || value.length === 0) {
    return parseFloat(0);
  } else {
    return parseFloat(value);
  }
};
scwin.f_copybuytosell = function () {
  scwin.f_Update();
  var IL015_COMMON_CODE = [];
  var str = "";
  var temp = "";
  var temp2 = [];
  var IL015 = [];

  // TODO: server-side code list conversion needed
  var rowCount = dlt_commonCodeIL005.getRowCount();
  for (var i = 0; i < rowCount; i++) {
    IL015.push(dlt_commonCodeIL005.getCellData(i, "cd"));
  }
  ds_selling.setRowPosition(ds_selling.getRowCount());
  var k = ds_selling.getRowCount() + 1;
  for (var a = 1; a <= ds_buying.getRowCount(); a++) {
    var num = -2;
    var fareEngCd = ds_buying.getCellData(a - 1, "fareEngCd");
    for (var b = 0; b < IL015.length; b = b + 2) {
      if (IL015[b] == fareEngCd) {
        scwin.f_addRow(1);
        num = b;
        break;
      }
    }
    if (num != -2) {
      ds_selling.setCellData(k - 1, "fareEngNm", "");
      ds_selling.setCellData(k - 1, "fareEngCd", IL015[num + 1]);
      scwin.f_PopUpGrid("SellingFcode", k, "T", "F", "F");
      ds_selling.setCellData(k - 1, "fareUnit", ds_buying.getCellData(a - 1, "fareUnit"));
      ds_selling.setCellData(k - 1, "chgWt", ds_buying.getCellData(a - 1, "chgWt"));
      ds_selling.setCellData(k - 1, "sellUpr", ds_buying.getCellData(a - 1, "pchsUpr"));
      ds_selling.setCellData(k - 1, "rsltsStdDt", ds_buying.getCellData(a - 1, "rsltsStdDt"));
      if (ds_selling.getCellData(k - 1, "fareEngCd") == "DOC") {
        ds_selling.setCellData(k - 1, "sellAmtFcrc", ds_buying.getCellData(a - 1, "pchsAmtFcrc"));
      }
      var Colid = "";
      var olddata = "";
      scwin.f_sellingAmtFcrc(k, Colid, olddata);
      scwin.f_sellingAmt(k, Colid, olddata);
      scwin.f_sellingUsdAmt(k, Colid, olddata);
      scwin.f_sellingVat(k, Colid, olddata);
      scwin.f_SellingSum();
      k = k + 1;
      gr_selling.focus();
      var rowIdx = ds_selling.getRowPosition();
      gr_selling.setFocusedCell(rowIdx == null ? 0 : rowIdx, "sellSeq", true); // focus
    }
  }
  tab_main.setSelectedTabIndex(0);
};

