scwin.f_sellingAmt = function (Row, Colid, olddata) {
  if (ds_selling.getCellData(Row, "crcCd") == "KRW") {
    ds_selling.setCellData(Row, "sellAmt", Math.round(Number(ds_selling.getCellData(Row, "chgWt")) * Number(ds_selling.getCellData(Row, "sellUpr"))));
  } else if (ds_selling.getCellData(Row, "crcCd") == "JPY" || ds_selling.getCellData(Row, "crcCd") == "ITL" || ds_selling.getCellData(Row, "crcCd") == "IDR" || ds_selling.getCellData(Row, "crcCd") == "ESP") {
    ds_selling.setCellData(Row, "sellAmt", Math.round(Number(ds_selling.getCellData(Row, "sellAmtFcrc")) * Number(ds_selling.getCellData(Row, "exRate"))) / 100);
  } else {
    ds_selling.setCellData(Row, "sellAmt", Math.round(Number(ds_selling.getCellData(Row, "sellAmtFcrc")) * Number(ds_selling.getCellData(Row, "exRate"))));
  }
};
scwin.f_sellingAmtFcrc = function (Row, Colid, olddata) {
  if (ds_selling.getCellData(Row, "crcCd") == "KRW") {
    ds_selling.setCellData(Row, "sellAmtFcrc", "0");
  } else {
    ds_selling.setCellData(Row, "sellAmtFcrc", Math.round(Number(ds_selling.getCellData(Row, "chgWt")) * Number(ds_selling.getCellData(Row, "sellUpr")) * 100) / 100);
  }
};
