scwin.gr_partner_onviewchange = function (info) {
  //rowIndex, columnIndex, value
  let row = info.rowIndex;
  let col = info.colId;
  let olddata = info.oldValue;
  let value = info.newValue;
  if (row < 0 || ds_partner.getRowCount() <= row) return;
  switch (col) {
    case "bilgClntNo":
      if (!$c.util.isEmpty($p, value)) {
        ds_partner.setCellData(row, "bilgClntNm", "");
        scwin.f_PopUpGrid("PartnerCustomer", row, "T", "F", "F");
      } else {
        ds_partner.setCellData(row, "bilgClntNo", "");
        ds_partner.setCellData(row, "bilgClntNm", "");
      }
      break;
    case "fareEngCd":
      if (!$c.util.isEmpty($p, value)) {
        ds_partner.setCellData(row, "fareEngNm", "");
        ds_partner.setCellData(row, "fareEngCd", value.toUpperCase());
        scwin.f_PopUpGrid("PartnerFcode", row, "T", "F", "F");
      } else {
        ds_partner.setCellData(row, "fareEngCd", "");
        ds_partner.setCellData(row, "fareEngNm", "");
      }
      scwin.f_partnerAmtFcrc(row, col, olddata);
      scwin.f_partnerAmt(row, col, olddata);
      scwin.f_partnerUsdAmt(row, col, olddata);
      break;
    case "crcCd":
    case "chgWt":
    case "sellUpr":
      scwin.f_partnerAmtFcrc(row, col, olddata);
      scwin.f_partnerAmt(row, col, olddata);
      scwin.f_partnerUsdAmt(row, col, olddata);
      break;
    case "exRate":
      scwin.f_partnerAmt(row, col, olddata);
      break;
    case "sellAmt":
      scwin.f_partnerUsdAmt(row, col, olddata);
      break;
    case "fareUnit":
      // gr_partner event=OnCloseUp(Row,Colid)
      scwin.f_packageRatePartnerLoading(row, col);
      scwin.f_partnerTariffRateLoading();
      break;
  }
};
