scwin.sbm_retrieve_submitdone = async function (e) {
  txt_totalSelling.setValue(ds_selling.getRowCount());
  txt_totalPartner.setValue(ds_partner.getRowCount());
  txt_totalBuying.setValue(ds_buying.getRowCount());
  var hhbkgseq = ds_houseblList.getRowPosition() >= 0 ? ds_houseblList.getCellData(0, "hhbkgseq") : "";
  if (hhbkgseq) {
    ds_bkseq.setCellData(0, "code", hhbkgseq);
    ds_bkseq.setCellData(0, "name", hhbkgseq);
  }
  if (ds_houseblList.getRowCount() === 0) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003);
    scwin.f_Set("INIT");
    scwin.f_Check();
    return;
  }
  ds_houseblList.setRowPosition(0);
  scwin.ds_houseblList_ondataload();

  //ds_houseblList.setRowPosition(0);
  ds_ocContList.setRowPosition(0);
  ds_slipTax.setRowPosition(0);
  ds_ocProfitList.setRowPosition(0);

  // 컨테이너 합계
  var totPkg = 0,
    totWgt = 0,
    totMsr = 0;
  var rc = ds_ocContList.getRowCount();
  for (var i = 0; i < rc; i++) {
    totPkg += Number(ds_ocContList.getCellData(i, "mcpkg") || 0);
    totWgt += Number(ds_ocContList.getCellData(i, "mcwgt") || 0);
    totMsr += Number(ds_ocContList.getCellData(i, "mcmsr") || 0);
  }
  ed_totpkg.setValue(totPkg);
  ed_totwgt.setValue(totWgt);
  ed_totmsr.setValue(totMsr);
  scwin.f_invoiceCheck();
  scwin.f_Set("RETRIEVE");

  // Booking seq combo 값 세팅
  if (ds_bkseq.getRowCount() === 0) {
    ds_bkseq.insertRow(0);
  }
  ds_bkseq.setCellData(0, "code", ds_houseblList.getCellData(0, "hhbkgseq") || "");
  lc_hhbkgseq.setValue(ds_bkseq.getCellData(0, "code"));
  scwin.f_ContractInfo();
  $c.gus.cfEnableObj($p, cnd_ed_hhblno, true);
  $c.gus.cfEnableObj($p, cnd_lc_mhno, true);

  // Profit 조회
  ds_profit.removeAll();
  await $c.sbm.execute($p, sbm_retrieveProfit);
  ds_profit.setRowPosition(0);

  // Freight 조회
  $c.sbm.execute($p, sbm_retrieve1);
  scwin.f_sellingUnitLoading();
  scwin.f_partnerUnitLoading();
  scwin.f_buyingUnitLoading();

  // tr_retrieve1" event="OnSuccess()"
  if (ds_houseblList.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  
    scwin.f_Set("INIT");
    scwin.f_Check(); // Object Check			
  } else {
    scwin.f_invoiceCheck(); // invoice Check
    scwin.f_Set("RETRIEVE");
    scwin.f_SellingSum();
    scwin.f_PartnerSum();
    scwin.f_BuyingSum();
  }

  // 계약/컨테이너 booking 조회
  dma_retrieveCtrtClnt.set("kcomcd", scwin.hd_kcomcd);
  dma_retrieveCtrtClnt.set("bkNo", ed_hhbkgno.getValue());
  $c.sbm.execute($p, sbm_ctrtRetrieve);
  scwin.f_setFileUpDownFrame();
};
