scwin.f_RunExcel = async function (varGrNm) {
  let cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
  if (!cfrm) return;
  let filename = "Container List_" + cnd_ed_hhblno.getValue();
  let options = {
    fileName: filename + ".xlsx",
    sheetName: filename
  };
  $c.data.downloadGridViewExcel($p, gr_ocContList, options, []);
};
scwin.sbm_retrievePartner_submitdone = function (e) {
  // 개별 조회 시 서버 미반환 컬럼 세팅
  for (var i = 0; i < ds_partner.getRowCount(); i++) {
    if ($c.util.isEmpty($p, ds_partner.getCellData(i, "drcrCls"))) {
      ds_partner.setCellData(i, "drcrCls", "C");
    }
    if (ds_partnerUnit.getRowCount() > 0) {
      ds_partner.setCellData(i, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
    }
  }
  scwin.f_PartnerSum();
};
scwin.sbm_retrieveBuying_submitdone = function (e) {
  // 개별 조회 시 서버 미반환 컬럼 세팅
  for (var i = 0; i < ds_buying.getRowCount(); i++) {
    if (ds_buyingUnit.getRowCount() > 0) {
      ds_buying.setCellData(i, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
    }
    if ($c.util.isEmpty($p, ds_buying.getCellData(i, "rsltsStdDt"))) {
      ds_buying.setCellData(i, "rsltsStdDt", $c.date.addDate($p, scwin.strCurDate, 1));
    }
  }
  scwin.f_BuyingSum();
};
